      teachingPoints: [
        {cn: "\u4f53\u4f1a\u8bbd\u523a\u5c0f\u8bf4\u7684\u8868\u73b0\u624b\u6cd5\uff0c\u7406\u89e3\u5bf9\u6bd4\u3001\u5938\u5f20\u5728\u8bbd\u523a\u4e2d\u7684\u4f5c\u7528", en: "Appreciate the techniques of satirical fiction; understand the roles of contrast and exaggeration in satire"},
        {cn: "\u8ba4\u8bc6\u79d1\u4e3e\u5236\u5ea6\u5bf9\u53e4\u4ee3\u8bfb\u4e66\u4eba\u7684\u5f71\u54cd", en: "Recognize the impact of the imperial examination system on ancient scholars"}
      ],
      parentTips: [{cn: "\u548c\u5b69\u5b50\u8ba8\u8bba\u201c\u529f\u540d\u201d\u4e0e\u201c\u4ef7\u503c\u89c2\u201d\u7684\u5173\u7cfb\uff0c\u5f15\u5bfc\u5065\u5eb7\u7684\u6210\u529f\u89c2", en: "Discuss the relationship between fame/status and values with your child; guide them toward a healthy view of success"}]
