      teachingPoints: [{cn: "\u611f\u53d7\u53e4\u4ee3\u5c0f\u8bf4\u5bf9\u5386\u53f2\u6545\u4e8b\u7684\u6f14\u7ece\u624b\u6cd5\uff0c\u4f53\u4f1a\u4eba\u7269\u5bf9\u8bdd\u7684\u8868\u73b0\u529b", en: "Appreciate how classical novels dramatize historical stories; experience the expressive power of character dialogue"}],
